import{_ as t,o as i,c as s,a5 as e}from"./chunks/framework.D9Kapg2s.js";const k=JSON.parse('{"title":"翻译审校","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/review.md","filePath":"zh/guide/review.md"}'),l={name:"zh/guide/review.md"};function d(r,a,n,o,h,p){return i(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="翻译审校" tabindex="-1">翻译审校 <a class="header-anchor" href="#翻译审校" aria-label="Permalink to &quot;翻译审校&quot;">​</a></h1><p>翻译审校功能帮助您确保翻译质量，支持逐段审校、内联编辑和批量操作。</p><h2 id="审校流程" tabindex="-1">审校流程 <a class="header-anchor" href="#审校流程" aria-label="Permalink to &quot;审校流程&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>翻译完成 → 逐段审校 → 编辑/批注 → 审批/拒绝 → 完成</span></span></code></pre></div><p>翻译作业完成后的段落状态为「已翻译」，进入审校阶段。您也可以在创建翻译作业时开启 <strong>自动审批</strong>，跳过审校流程。</p><h2 id="段落状态" tabindex="-1">段落状态 <a class="header-anchor" href="#段落状态" aria-label="Permalink to &quot;段落状态&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态</th><th>说明</th><th>可转换为</th></tr></thead><tbody><tr><td>待审校 (<code>pending</code>)</td><td>等待翻译</td><td>—</td></tr><tr><td>已翻译 (<code>translated</code>)</td><td>AI 翻译完成，等待审校</td><td>已批准、已驳回、已修改</td></tr><tr><td>已修改 (<code>edited</code>)</td><td>人工编辑后的状态</td><td>已批准、已驳回</td></tr><tr><td>已批准 (<code>approved</code>)</td><td>审校通过</td><td>—</td></tr><tr><td>已驳回 (<code>rejected</code>)</td><td>审校不通过</td><td>已批准、已修改、待审校（重新翻译）</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">状态流转</p><ul><li>审批操作可从「已翻译」「已修改」「已驳回」转换为「已批准」</li><li>驳回操作可从「已翻译」「已修改」转换为「已驳回」</li><li>已批准的段落不能直接驳回，需要先编辑修改</li></ul></div><h2 id="逐段审校" tabindex="-1">逐段审校 <a class="header-anchor" href="#逐段审校" aria-label="Permalink to &quot;逐段审校&quot;">​</a></h2><p>翻译完成后，在工作区的段落列表中逐段查看和审校翻译结果。</p><h3 id="审校界面" tabindex="-1">审校界面 <a class="header-anchor" href="#审校界面" aria-label="Permalink to &quot;审校界面&quot;">​</a></h3><p>每段显示以下信息：</p><ul><li><strong>源文本</strong> — 原始内容，可切换查看 HTML 源码</li><li><strong>翻译文本</strong> — AI 翻译结果</li><li><strong>状态标签</strong> — 带图标和颜色的状态标识（蓝色=待审校，绿色=已批准，红色=已驳回）</li><li><strong>质量指示</strong> — 在译文单元格内显示质量检测结果（长度异常、重复翻译、未翻译、源语残留等）</li><li><strong>审校批注</strong> — 审校者添加的备注信息，点击可展开查看</li></ul><h3 id="段落导航" tabindex="-1">段落导航 <a class="header-anchor" href="#段落导航" aria-label="Permalink to &quot;段落导航&quot;">​</a></h3><p>段落表格支持键盘上下导航：</p><ul><li><strong>↑ / ↓</strong> 键移动聚焦行</li><li>自动滚动确保聚焦行不会被表格头部遮挡</li><li>进入编辑时自动聚焦输入框</li></ul><h3 id="审校操作" tabindex="-1">审校操作 <a class="header-anchor" href="#审校操作" aria-label="Permalink to &quot;审校操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>说明</th><th>状态变化</th></tr></thead><tbody><tr><td>✅ 审批</td><td>确认翻译正确</td><td>→ <code>approved</code></td></tr><tr><td>❌ 拒绝</td><td>标记翻译有问题</td><td>→ <code>rejected</code></td></tr><tr><td>✏️ 编辑</td><td>内联编辑翻译内容</td><td>→ <code>edited</code></td></tr></tbody></table><h2 id="内联编辑" tabindex="-1">内联编辑 <a class="header-anchor" href="#内联编辑" aria-label="Permalink to &quot;内联编辑&quot;">​</a></h2><p>点击编辑按钮可以直接修改翻译内容和添加批注：</p><ol><li>点击段落的编辑按钮，输入框自动获得焦点</li><li>在编辑框中修改翻译文本</li><li>可选填写审校批注，记录修改原因</li><li>点击 <strong>保存</strong> 确认修改，或使用 <strong>「保存并下一个」</strong> 快捷进入下一段编辑</li></ol><div class="tip custom-block"><p class="custom-block-title">编辑后自动审批</p><p>编辑保存后的段落状态会变为「已修改」(<code>edited</code>)，仍需手动审批。</p></div><h2 id="质量检测" tabindex="-1">质量检测 <a class="header-anchor" href="#质量检测" aria-label="Permalink to &quot;质量检测&quot;">​</a></h2><p>LinguaFlow 在翻译完成后自动检测译文中可能存在的问题，帮助您快速定位需要关注的段落。</p><h3 id="检测规则" tabindex="-1">检测规则 <a class="header-anchor" href="#检测规则" aria-label="Permalink to &quot;检测规则&quot;">​</a></h3><table tabindex="0"><thead><tr><th>检测类型（code）</th><th>说明</th><th>可 AI 裁决</th></tr></thead><tbody><tr><td><strong>长度异常</strong>（<code>length_ratio</code>）</td><td>译文长度与原文相差过大（过短或过长）；可配置最小/最大长度比、按字符或按词计算</td><td>✅ 软规则</td></tr><tr><td><strong>重复翻译</strong>（<code>duplicate</code>）</td><td>相邻段落译文完全相同</td><td>❌ 硬规则</td></tr><tr><td><strong>未翻译</strong>（<code>untranslated</code>）</td><td>译文与原文完全一致，可能未被翻译</td><td>❌ 硬规则</td></tr><tr><td><strong>源语残留</strong>（<code>source_residual</code>）</td><td>译文中夹带源语脚本片段（如假名、谚文、西里尔文、汉字残留等），按语言对自动匹配规则</td><td>✅ 软规则</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">源语残留</p><p>检测器按源/目标语言对解析 Unicode 脚本规则：独立脚本（假名、谚文等）为强档；汉字在不同语言对间有准强 / 中等 / 弱档策略。专有名词、代码、刻意保留原文等场景可能产生误报，可配合 <a href="/zh/guide/advanced.html#ai-质量裁决">质量裁决轮次</a> 降噪。</p></div><h3 id="质量指示" tabindex="-1">质量指示 <a class="header-anchor" href="#质量指示" aria-label="Permalink to &quot;质量指示&quot;">​</a></h3><p>检测到问题后，段落表格的质量指标列会显示对应的状态标记：</p><ul><li><strong>绿色</strong> — 无问题</li><li><strong>黄色</strong> — 轻微问题（如源语残留、长度轻微偏差）</li><li><strong>红色</strong> — 严重问题（如过长/过短超出阈值、重复、未翻译）</li></ul><p>点击质量标记可查看详细诊断信息（含问题 code 与说明）。</p><h3 id="质量检测配置" tabindex="-1">质量检测配置 <a class="header-anchor" href="#质量检测配置" aria-label="Permalink to &quot;质量检测配置&quot;">​</a></h3><p>在执行配置（Execution Profile）中调整质量检测参数：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">qa</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 是否启用质量检测</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  length</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 长度异常检测</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    min_ratio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.5</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 最小长度比（译文/原文）</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    max_ratio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.5</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 最大长度比</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    unit</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">char</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 计算方式：char（字符数）或 word（词数）</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  repetition</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 重复翻译检测</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  untranslated</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 未翻译检测</span></span></code></pre></div><p>源语残留检测随质量检测引擎自动启用，无需单独开关（源语言为 <code>auto</code> 时不生效，需指定明确语言对）。</p><h2 id="批注" tabindex="-1">批注 <a class="header-anchor" href="#批注" aria-label="Permalink to &quot;批注&quot;">​</a></h2><p>在审校过程中可以为每个段落添加批注，记录修改原因或翻译建议。</p><p>批注存储在段落的 <code>review_comment</code> 字段中，在段落列表中可以查看。</p><div class="info custom-block"><p class="custom-block-title">使用场景</p><ul><li>记录修改翻译的原因</li><li>标记需要后续复查的术语</li><li>为其他审校者提供参考意见</li></ul></div><h2 id="批量操作" tabindex="-1">批量操作 <a class="header-anchor" href="#批量操作" aria-label="Permalink to &quot;批量操作&quot;">​</a></h2><p>当翻译段落较多时，可以使用批量操作提高效率。</p><h3 id="选择段落" tabindex="-1">选择段落 <a class="header-anchor" href="#选择段落" aria-label="Permalink to &quot;选择段落&quot;">​</a></h3><p>在段落列表中勾选需要操作的段落，底部会弹出浮动操作栏。</p><h3 id="批量审批" tabindex="-1">批量审批 <a class="header-anchor" href="#批量审批" aria-label="Permalink to &quot;批量审批&quot;">​</a></h3><p>选择多个段落后，点击浮动操作栏的 <strong>通过</strong> 按钮，一次性审批所有选中的段落。</p><h3 id="批量拒绝" tabindex="-1">批量拒绝 <a class="header-anchor" href="#批量拒绝" aria-label="Permalink to &quot;批量拒绝&quot;">​</a></h3><p>选择多个段落后，点击浮动操作栏的 <strong>拒绝</strong> 按钮，一次性拒绝所有选中的段落。</p><div class="info custom-block"><p class="custom-block-title">批量操作说明</p><ul><li>批量审批时，仅对状态为「已翻译」「已修改」「已驳回」的段落生效</li><li>批量拒绝时，仅对状态为「已翻译」「已修改」的段落生效</li><li>不满足条件的段落会被自动跳过</li></ul></div><h2 id="一键审批" tabindex="-1">一键审批 <a class="header-anchor" href="#一键审批" aria-label="Permalink to &quot;一键审批&quot;">​</a></h2><p>在资源详情页，可以使用 <strong>全部审批</strong> 功能，将该资源下所有符合条件的段落一次性审批通过。</p><ul><li>将所有「已翻译」「已修改」「已驳回」状态的段落转为「已批准」</li><li>审批后自动清除这些段落的审校批注</li></ul><h2 id="重新翻译已驳回段落" tabindex="-1">重新翻译已驳回段落 <a class="header-anchor" href="#重新翻译已驳回段落" aria-label="Permalink to &quot;重新翻译已驳回段落&quot;">​</a></h2><p>对于已驳回的段落，可以触发 <strong>重新翻译</strong>，将这些段落重置为「待审校」状态并重新进入翻译队列。</p><ul><li>所有「已驳回」状态的段落会被重置为「待审校」</li><li>清除审校者信息和审校批注</li></ul><h2 id="自动审批" tabindex="-1">自动审批 <a class="header-anchor" href="#自动审批" aria-label="Permalink to &quot;自动审批&quot;">​</a></h2><p>创建翻译任务时，可以开启 <strong>自动审批</strong> 选项：</p><ul><li>开启后，翻译完成的段落会直接标记为「已批准」，无需手动审校</li><li>适用于对翻译质量要求不高的场景或初稿翻译</li></ul><p>在任务创建面板中，勾选「翻译完成后自动审批」即可启用。</p><h2 id="审校进度" tabindex="-1">审校进度 <a class="header-anchor" href="#审校进度" aria-label="Permalink to &quot;审校进度&quot;">​</a></h2><p>工作区顶部的进度条显示翻译和审校进度：</p><ul><li><strong>蓝色进度条</strong> — 已翻译段落占比（包含已翻译、已修改、已批准）</li><li><strong>绿色进度条</strong> — 已审批段落占比（仅已批准）</li></ul><p>段落分组也会显示每组的已批准数量和占比。</p><h2 id="搜索与筛选" tabindex="-1">搜索与筛选 <a class="header-anchor" href="#搜索与筛选" aria-label="Permalink to &quot;搜索与筛选&quot;">​</a></h2><p>在段落列表中可以搜索和筛选，快速定位需要审校的段落。</p><h3 id="搜索" tabindex="-1">搜索 <a class="header-anchor" href="#搜索" aria-label="Permalink to &quot;搜索&quot;">​</a></h3><p>在段落列表顶部的搜索框中输入关键词，可以同时搜索原文和译文内容。搜索为模糊匹配，输入任意关键词即可筛选出包含该内容的段落。</p><div class="tip custom-block"><p class="custom-block-title">搜索与筛选可叠加</p><p>搜索可以与状态筛选同时使用。例如，先筛选「已驳回」状态，再搜索特定术语，快速找到需要修改的段落。</p></div><h3 id="按状态筛选" tabindex="-1">按状态筛选 <a class="header-anchor" href="#按状态筛选" aria-label="Permalink to &quot;按状态筛选&quot;">​</a></h3><p>在段落列表中可以按状态筛选：</p><ul><li>筛选「已翻译」— 查看待审校的段落</li><li>筛选「已驳回」— 查看需要重新处理的段落</li><li>筛选「已批准」— 查看已通过的段落</li><li>筛选「已修改」— 查看人工编辑过的段落</li></ul><h3 id="按质量问题筛选" tabindex="-1">按质量问题筛选 <a class="header-anchor" href="#按质量问题筛选" aria-label="Permalink to &quot;按质量问题筛选&quot;">​</a></h3><p>段落列表支持按质量问题过滤，快速定位需关注的段落：</p><table tabindex="0"><thead><tr><th>筛选维度</th><th>选项</th></tr></thead><tbody><tr><td>有无问题</td><td><code>有问题</code> / <code>无问题</code></td></tr><tr><td>严重程度</td><td><code>error</code> / <code>warning</code></td></tr><tr><td>问题类型</td><td><code>untranslated</code> / <code>length_ratio</code> / <code>duplicate</code> / <code>source_residual</code></td></tr></tbody></table><p>可与状态筛选、关键词搜索叠加。例如：先筛「有问题」+ <code>source_residual</code>，再结合状态「已翻译」，集中处理源语残留。</p><div class="tip custom-block"><p class="custom-block-title">配合 AI 质量裁决</p><p>规则质检偏敏感，难免误报。可在执行计划中增加 <strong>质量裁决</strong>（<code>adjudicate</code>）轮次，让 AI 对 <code>source_residual</code>、<code>length_ratio</code> 等软规则逐条复核，剔除明确误报后再人工审校。详见 <a href="/zh/guide/advanced.html#ai-质量裁决">高级功能 · AI 质量裁决</a>。</p></div><h2 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to &quot;最佳实践&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">审校建议</p><ol><li><strong>分批审校</strong> — 按章节或段落分批审校，避免疲劳</li><li><strong>关注术语</strong> — 重点检查专业术语的翻译是否一致</li><li><strong>保持上下文</strong> — 审校时注意段落之间的连贯性</li><li><strong>记录批注</strong> — 为重要的修改添加批注，方便后续参考</li><li><strong>善用筛选</strong> — 按状态与质量问题筛选，优先处理有问题的段落</li><li><strong>批量操作</strong> — 段落较多时使用批量审批/拒绝提高效率</li><li><strong>裁决降噪</strong> — 启用质量裁决轮次，减少源语残留、长度异常的误报干扰</li></ol></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>阅读 <a href="/zh/guide/glossary.html">术语表管理</a> 了解术语管理</li><li>阅读 <a href="/zh/guide/advanced.html">高级功能</a> 了解更多高级功能</li></ul>`,79)])])}const u=t(l,[["render",d]]);export{k as __pageData,u as default};
